"use client";

import * as React from "react";
import { type MotionValue, useMotionValue, useMotionValueEvent } from "motion/react";

import { cn } from "@/lib/utils";
import { clamp01, useExperienceViewport, usePrefersReducedMotion } from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";

export type DrawOnScrollProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  /** Inline SVG content whose stroked shapes get drawn. */
  children: React.ReactNode;
  /**
   * 0 draws every shape simultaneously; 1 draws them strictly one after
   * another; values in between overlap the strokes.
   */
  stagger?: number;
  /** Pin the section and drive drawing across this many scroll screens. */
  pin?: boolean;
  scrollScreens?: number;
  /** External progress override (0..1). */
  progress?: MotionValue<number>;
  /** Bump to re-measure after the SVG content changes. */
  remeasureKey?: React.Key;
  stageClassName?: string;
};

type StrokeTarget = { element: SVGGeometryElement; length: number };

/** Progress of a non-pinned element through the viewport: 0 entering from the bottom, 1 leaving the top. */
function useViewportProgress(target: React.RefObject<HTMLElement | null>, enabled: boolean) {
  const progress = useMotionValue(0);
  React.useEffect(() => {
    const element = target.current;
    if (!element || !enabled) return;
    let frame = 0;
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(() => {
        const rect = element.getBoundingClientRect();
        const viewport = window.innerHeight;
        progress.set(clamp01((viewport - rect.top) / Math.max(1, viewport + rect.height)));
      });
    };
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    update();
    return () => {
      cancelAnimationFrame(frame);
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [enabled, progress, target]);
  return progress;
}

/**
 * Draws the stroked shapes of an inline SVG as the section moves through the
 * viewport (or across a pinned range). Reduced-motion users see the finished
 * drawing.
 */
export function DrawOnScroll({
  children,
  className,
  label,
  pin = false,
  progress: controlledProgress,
  remeasureKey,
  scrollScreens = 2,
  stageClassName,
  stagger = 0.35,
  ...props
}: DrawOnScrollProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const stageRef = React.useRef<HTMLDivElement>(null);
  const targetsRef = React.useRef<StrokeTarget[]>([]);
  const reducedMotion = usePrefersReducedMotion();
  const viewport = useExperienceViewport();
  const activePin = pin && viewport !== "mobile";
  const activeStagger = stagger * (viewport === "mobile" ? .72 : viewport === "tablet" ? .86 : 1);

  const pinnedProgress = useElementScrollProgress(rootRef);
  const viewportProgress = useViewportProgress(rootRef, !activePin && !controlledProgress && !reducedMotion);
  const progress = controlledProgress ?? (activePin ? pinnedProgress : viewportProgress);

  const applyProgress = React.useCallback(
    (value: number) => {
      const targets = targetsRef.current;
      const count = targets.length;
      if (count === 0) return;
      const span = 1 / (1 + (count - 1) * clamp01(activeStagger));
      const step = count > 1 ? (1 - span) / (count - 1) : 0;
      targets.forEach(({ element, length }, index) => {
        const local = clamp01((value - index * step) / span);
        element.style.strokeDashoffset = `${length * (1 - local)}`;
      });
    },
    [activeStagger],
  );

  React.useLayoutEffect(() => {
    const stage = stageRef.current;
    if (!stage) return;
    const shapes = Array.from(
      stage.querySelectorAll<SVGGeometryElement>("path, circle, ellipse, line, polyline, polygon, rect"),
    ).filter((shape) => typeof shape.getTotalLength === "function");
    if (reducedMotion) {
      shapes.forEach((shape) => {
        shape.style.strokeDasharray = "";
        shape.style.strokeDashoffset = "";
      });
      targetsRef.current = [];
      return;
    }
    targetsRef.current = shapes.map((element) => {
      let length = 0;
      try {
        length = element.getTotalLength();
      } catch {
        length = 0;
      }
      element.style.strokeDasharray = `${length}`;
      return { element, length };
    });
    applyProgress(progress.get());
  }, [applyProgress, progress, reducedMotion, remeasureKey]);

  useMotionValueEvent(progress, "change", (value) => {
    if (!reducedMotion) applyProgress(value);
  });

  if (reducedMotion) {
    return (
      <section ref={rootRef} aria-label={label} data-draw-on-scroll data-experience-viewport={viewport} data-static className={cn("relative", className)} {...props}>
        <div ref={stageRef} className={stageClassName}>
          {children}
        </div>
      </section>
    );
  }

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-draw-on-scroll
      data-experience-viewport={viewport}
      data-pin={activePin || undefined}
      className={cn("relative", className)}
      style={activePin ? { minHeight: `${Math.max(1, scrollScreens) * 100}svh` } : undefined}
      {...props}
    >
      <div ref={stageRef} className={cn(activePin && "sticky top-0 flex h-svh items-center justify-center overflow-hidden", stageClassName)}>
        {children}
      </div>
    </section>
  );
}

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` → `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
  mode: "pinned" | "entry" = "pinned",
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const measure = () => {
      const rect = element.getBoundingClientRect();
      const value = mode === "entry"
        ? (window.innerHeight - rect.top) / Math.max(1, element.offsetHeight)
        : -rect.top / Math.max(1, element.offsetHeight - window.innerHeight);
      progress.set(Math.max(0, Math.min(1, value)));
    };
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(measure);
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    // Synchronous first measurement: consumers that render a bootstrap frame
    // before the first animation frame (e.g. a restored scroll position in a
    // background tab) already see the true progress.
    measure();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [mode, progress, target]);

  return progress;
}
